@namespace Lumeo

@{
    var context = new SheetContext(Open, EventCallback.Factory.Create<bool>(this, SetOpen), _titleId, _descriptionId, TryDismiss, _descriptionRegistry, RegisterDescription, UnregisterDescription);
}

<CascadingValue Value="context" IsFixed="false">
    @ChildContent
</CascadingValue>

@code {
    /// <summary>The trigger and content that make up the sheet (typically a <c>SheetTrigger</c> plus a <c>SheetContent</c>).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Whether the sheet panel is open. Controlled together with <see cref="OpenChanged"/>.</summary>
    [Parameter] public bool Open { get; set; }

    /// <summary>Fires whenever the open state changes (trigger click, Escape, swipe, backdrop click, or a <c>SheetClose</c> trigger).</summary>
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>
    /// Fires before any user-initiated dismiss (Escape, backdrop click,
    /// swipe gesture, X button, or a <c>SheetClose</c> trigger). Set
    /// <see cref="DismissEventArgs.Cancel"/> to <c>true</c> to abort. The
    /// <see cref="DismissEventArgs.Reason"/> tells you which path fired
    /// (<c>"escape"</c>, <c>"outside"</c>, <c>"swipe"</c>, <c>"close"</c>).
    /// </summary>
    [Parameter] public EventCallback<DismissEventArgs> OnBeforeClose { get; set; }

    /// <summary>Obsolete alias for <see cref="Open"/>; will be removed in a future release.</summary>
    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    /// <summary>Obsolete alias for <see cref="OpenChanged"/>; will be removed in a future release.</summary>
    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    private readonly string _titleId = LumeoIds.New("sheet-title");
    private readonly string _descriptionId = LumeoIds.New("sheet-desc");

    // Tracks whether a <SheetDescription> is actually present in the tree. A
    // mutable holder (not a record field) because the cascaded context is
    // rebuilt every render, but the registration must persist across renders.
    // Mirrors AlertDialog's DescriptionRegistry — without this SheetContent
    // would emit a dangling aria-describedby IDREF whenever no description is
    // rendered (e.g. every service-opened overlay).
    private readonly SheetDescriptionRegistry _descriptionRegistry = new();

    private async Task SetOpen(bool value)
    {
        Open = value;
        await OpenChanged.InvokeAsync(value);
    }

    private async Task<bool> TryDismiss(string reason)
    {
        if (OnBeforeClose.HasDelegate)
        {
            var args = new DismissEventArgs { Reason = reason };
            await OnBeforeClose.InvokeAsync(args);
            if (args.Cancel) return false;
        }
        await SetOpen(false);
        return true;
    }

    // Called by SheetDescription on init so SheetContent only wires
    // aria-describedby when a description actually exists (no dangling IDREF).
    // Re-renders so the content's aria-describedby picks up the registration on
    // the next pass (child OnInitialized runs after the parent's first render).
    // Counted (not a bool) so a description that is conditionally REMOVED while
    // the sheet stays mounted is correctly un-registered via UnregisterDescription
    // below (Codex P2) — a bare bool latched true forever.
    private void RegisterDescription()
    {
        _descriptionRegistry.Count++;
        if (_descriptionRegistry.Count == 1) StateHasChanged();
    }

    // Called by SheetDescription.Dispose when it is removed from the tree.
    // Only re-renders on the 1->0 transition.
    private void UnregisterDescription()
    {
        _descriptionRegistry.Count--;
        if (_descriptionRegistry.Count == 0) StateHasChanged();
    }

    // DescriptionRegistry + RegisterDescription/UnregisterDescription default to null! so the 4.0
    // additions stay a non-breaking signature change: Lumeo always constructs the context with real
    // values, and any external 3.x constructor of the 5-arg shape still compiles.
    public record SheetContext(bool IsOpen, EventCallback<bool> SetOpen, string TitleId, string DescriptionId, Func<string, Task<bool>> TryDismiss, SheetDescriptionRegistry DescriptionRegistry = null!, Action RegisterDescription = null!, Action UnregisterDescription = null!);

    /// <summary>
    /// Persistent, mutable holder that survives the per-render rebuild of
    /// <see cref="SheetContext"/>. Lets <see cref="SheetContent"/> know whether a
    /// <see cref="SheetDescription"/> is CURRENTLY rendered so it can avoid
    /// emitting a dangling <c>aria-describedby</c> IDREF (mirrors the AlertDialog
    /// pattern). A count, not a bool, so a description that mounts then is later
    /// removed un-registers.
    /// </summary>
    public sealed class SheetDescriptionRegistry
    {
        public int Count { get; set; }
        public bool HasDescription => Count > 0;
    }
}

@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

<div id="@_id" class="@CssClass" role="button" tabindex="0" @onclick="Close" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Sheet.SheetContext Context { get; set; } = default!;
    /// <summary>The trigger's content (typically close-button label or icon markup).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Additional CSS classes merged onto the trigger's root element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the trigger's root element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _fallbackId = LumeoIds.New("sheet-close");
    // A consumer-supplied id (splatted) wins, so JS key-suppression must target THAT id.
    private string _id => LumeoIds.Effective(AdditionalAttributes, _fallbackId);
    private bool _pdRegistered;

    private string CssClass => Cx.Merge("inline-flex", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender || _pdRegistered) return;
        try
        {
            // div[role=button] has no native key synthesis: Space both activated AND
            // scroll-jumped the page. Suppress only Space's default synchronously in
            // JS (Enter has no default on a div; a blanket @onkeydown:preventDefault
            // would also swallow Tab). Mirrors DialogClose / CollapsibleTrigger. #90
            await Interop.RegisterPreventDefaultKeys(
                _id,
                new[] { new Lumeo.Services.PreventDefaultKeyRule(" ") });
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    // Route through TryDismiss so OnBeforeClose handlers can guard the
    // close from a custom button just like the built-in X / Escape paths.
    private async Task Close() => await Context.TryDismiss("close");

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key is "Enter" or " ") await Close();
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_id);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}

@namespace Lumeo
@using Lumeo.Services
@implements IAsyncDisposable
@implements IOverlayExitCallback

@* <gotcha>No inner scroll container by default — the panel is a flex-col, so a long body overflows the viewport. Wrap the scrollable region in flex-1 overflow-y-auto, or use OverlayForm which bakes that in.</gotcha> *@

@if (Shell is not null)
{
    @* OverlayProvider already rendered the SheetContent shell around our parent
       component — rendering another shell here would stack a second backdrop +
       sliding panel on top. Pass the children straight through to the host
       shell instead. Side / Size / PreventClose / Class on this nested element
       are intentionally ignored; the provider controls those via OverlayOptions. *@
    @ChildContent
}
else if (Context.IsOpen || _exiting)
{
    @* pointer-events-none wrapper + -auto on backdrop/panel: the full-viewport
       wrapper must never be a hit-target itself — see DialogContent (B4 hardening). *@
    <div class="fixed inset-0 pointer-events-none" style="z-index:@BackdropZ">
        @* Backdrop — theme-aware --color-overlay-backdrop token via inline style
           (see DialogContent). Fades out alongside the panel while exiting. *@
        <div class="@BackdropClass" style="@BackdropStyle" @onclick="HandleBackdropClick"></div>
        @* @onkeydown:stopPropagation — keys handled inside this modal must not
           bubble into ancestor overlays (an Escape would cascade-close them).
           See DialogContent for the full rationale. *@
        @* While the panel is exiting (Context.IsOpen == false but kept mounted for the
           slide-out), its focus trap + scroll lock were already torn down by Cleanup(),
           so it is no longer a modal — advertise aria-modal="false" so the ARIA state
           matches the live behaviour instead of trapping AT on a non-trapping panel. #185 *@
        <div id="@_contentId" class="@CssClass" style="z-index:@ContentZ" role="dialog" aria-modal="@(Context.IsOpen ? "true" : "false")" aria-labelledby="@Context.TitleId" aria-describedby="@DescribedBy" @onkeydown="HandleKeyDown" @onkeydown:stopPropagation tabindex="-1" inert="@ExitInert" @attributes="AdditionalAttributes">
            @ChildContent
            @* lumeo-sheet-close: stable consumer hook; z-10 keeps the X above
               full-bleed positioned children (see DialogContent). *@
            @if (ShowCloseButton ?? !PreventClose)
            {
                <button type="button" aria-label="@L["Dialog.Close"]" class="lumeo-sheet-close absolute end-4 top-4 z-10 rounded-sm opacity-70 transition-opacity hover:opacity-100 focus:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2" @onclick="HandleCloseButton">
                    <SvgGlyph Svg="@(LumeoIcons.X)" class="h-4 w-4" />
                    <span class="sr-only">@L["Dialog.Close"]</span>
                </button>
            }
        </div>
    </div>
}

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject Microsoft.Extensions.Options.IOptions<Lumeo.Services.LumeoGestureOptions> GestureOpts
@inject Lumeo.Services.ThemeService Theme

@code {
    [CascadingParameter] public Sheet.SheetContext Context { get; set; } = default!;
    [CascadingParameter] public OverlayShellMarker? Shell { get; set; }
    /// <summary>The panel's content (typically a <c>SheetHeader</c>, body, and <c>SheetFooter</c>).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Edge of the viewport the panel slides in from / anchors to. Defaults to <see cref="Lumeo.Side.Right"/>. Mirrored under RTL so a "Right" sheet visually anchors to the start edge.</summary>
    [Parameter] public Lumeo.Side Side { get; set; } = Lumeo.Side.Right;

    /// <summary>Panel width (Left/Right sides) or height (Top/Bottom sides). Defaults to <see cref="SheetSize.Default"/>. Superseded by <see cref="SizePreset"/> when that is set.</summary>
    [Parameter] public SheetSize Size { get; set; } = SheetSize.Default;
    /// <summary>Alternative to <see cref="Size"/> that accepts the unified
    /// <see cref="Lumeo.Size"/> token. When set (non-null), wins over
    /// <see cref="Size"/>. Mapping: <c>Sm→Sm</c>, <c>Md→Default</c>,
    /// <c>Lg→Lg</c>, <c>Xl→Xl</c>. <see cref="SheetSize.Full"/> has no
    /// <see cref="Lumeo.Size"/> equivalent (Full is a layout intent, not a
    /// scale) — set <see cref="Size"/> directly for that case. Closes
    /// the <c>Lumeo.Size</c> ↔ per-component-enum overlap from #87.2.</summary>
    [Parameter] public Lumeo.Size? SizePreset { get; set; }
    /// <summary>How the sheet enters/leaves. <c>Slide</c> (default) animates
    /// from the configured <see cref="Side"/>. <c>Fade</c> uses a simple
    /// opacity tween — useful in dense forms where popovers and animations
    /// compete. <c>None</c> disables the animation entirely.</summary>
    [Parameter] public SheetAnimation Animation { get; set; } = SheetAnimation.Slide;
    /// <summary>When <c>true</c>, disables the backdrop click, Escape key and (per <see cref="ShowCloseButton"/>) default X-button dismiss paths, so the sheet can only be closed programmatically.</summary>
    [Parameter] public bool PreventClose { get; set; }
    /// <summary>Whether the top-end close (X) button renders. <c>null</c> (default)
    /// keeps the legacy coupling — X shows whenever <see cref="PreventClose"/> is
    /// <c>false</c>. <c>true</c> forces the X on a modal sheet (backdrop/Escape stay
    /// disabled; the X routes through the dismiss guard); <c>false</c> hides it.
    /// Mirrors <c>OverlayOptions.ShowCloseButton</c> for service sheets.</summary>
    [Parameter] public bool? ShowCloseButton { get; set; }
    /// <summary>When true, the sheet can be dismissed by swiping in the
    /// direction opposite to its Side (e.g. swipe-down on a Bottom sheet).
    /// Default false to avoid conflicts with scrollable content. Wire to
    /// true only when the sheet's content fits without scrolling.</summary>
    [Parameter] public bool SwipeToClose { get; set; } = false;

    /// <summary>Additional CSS classes merged onto the panel.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Backdrop z-index. Content sits at <c>ZIndex + 1</c>. Defaults
    /// to <see cref="OverlayService.BaseZIndex"/>; <see cref="OverlayProvider"/>
    /// supplies an incrementing value per nested overlay.</summary>
    [Parameter] public int ZIndex { get; set; } = OverlayService.BaseZIndex;

    /// <summary>Captures any unmatched attributes and applies them to the panel (ignored when rendered as a nested passthrough inside an <c>OverlayProvider</c> shell).</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("sheet");
    // True once we've rendered in the open state and not yet processed the close.
    // Drives the exit animation INDEPENDENTLY of whether the open-interop finished
    // (see OnParametersSetAsync). On Blazor Server the open interop chain (scroll
    // lock + focus trap + slide-end + swipe) is a sequence of round-trips; a user
    // can dismiss the panel WHILE they're still in flight. Gating the slide-out on
    // interop completion (the old `_wasOpen`) made those dismissals vanish with no
    // exit class — the B11 "service sheets don't animate out on real apps" report.
    private bool _shownOpen;
    // True once the open-interop chain has run and therefore needs tearing down on
    // close. Distinct from _shownOpen: on Server the panel is visible and
    // dismissable before this flips true.
    private bool _interopReady;
    // Exit-animation state: stays true between the close request and the moment
    // the slide/fade-out animation finishes, keeping the panel mounted so the
    // user sees it leave instead of vanishing. Driven by _exitDispatch.
    private bool _exiting;
    private readonly DelayedDispatch _exitDispatch = new();
    // Radix-Presence parity: once the exit render commits, hand the unmount to the
    // panel's OWN animationend (via attachOverlayExitEnd), which ALSO clears the
    // open-time inline animation:none guard so the slide-out can actually run. The
    // _exitDispatch above is now a strict FALLBACK (fires only if that JS callback
    // never arrives — circuit gone / event lost). _exitWired guards single wiring
    // per exit; reset whenever a new exit starts or the panel re-opens.
    private DotNetObjectReference<SheetContent>? _selfRef;
    private bool _exitWired;

    // Whether the swipe-to-dismiss gesture is currently wired in JS, plus the
    // direction it was registered with. Tracked so a PreventClose / SwipeToClose
    // / SwipeDirection change WHILE THE SHEET STAYS OPEN re-runs the
    // register/unregister pair (mirrors DrawerContent's _gestureRegistered),
    // instead of latching whatever was eligible at open time until a full
    // close+reopen. #89
    private bool _swipeRegistered;
    private string? _registeredSwipeDirection;

    // Whether swipe-to-dismiss should currently be wired given the live params.
    private bool SwipeEligible => !PreventClose && SwipeToClose;

    private int BackdropZ => ZIndex;
    private int ContentZ => ZIndex + 1;

    // Only reference the description id when a <SheetDescription> was actually
    // rendered; otherwise aria-describedby would dangle to a missing element
    // (returning null makes Blazor omit the attribute entirely). This is what
    // every service-opened Sheet (no description child) hits.
    private string? DescribedBy => Context.DescriptionRegistry.HasDescription ? Context.DescriptionId : null;

    // Slide-out is 0.3s (mirrors slide-in 0.3s); fade-out is 0.15s (mirrors
    // fade-in 0.15s). Both are symmetric enter/exit pairs. None unmounts
    // immediately (no exit phase). Values include a small buffer over the CSS
    // duration so the timer and the keyframe don't race on a loaded thread pool.
    // FALLBACK window only — the real unmount is driven by the panel's
    // animationend (OnExitAnimationEnd). These sit comfortably above the CSS
    // duration (slide 300ms, fade 150ms) so the timer never preempts a slightly
    // late animationend on the happy path; it exists solely for the JS-dead /
    // lost-event case. None has no exit phase (immediate unmount).
    private int ExitDurationMs => Animation switch
    {
        SheetAnimation.Slide => 450,
        SheetAnimation.Fade => 260,
        _ => 0,
    };

    // Slide-animation transform trap is fixed via JS interop:
    // Interop.AttachOverlaySlideEnd registers a native animationend listener
    // that filters strictly on slide-in-from-* AND on event.target === this
    // element (so descendant animations like Calendar's animate-zoom-in
    // don't trigger us), then sets inline `transform: none`. Inline style
    // beats the keyframe fill-mode forwarding — guarantees no containing
    // block trap for popovers (Select / DatePicker / Combobox).
    private string CssClass => Cx.Merge("fixed flex flex-col gap-4 bg-background p-6 shadow-lg", PositionClasses, AnimationClass, PointerClass, Class);

    // Exit-window inertness (mirrors DropdownMenuContent). While the panel is kept
    // mounted for the slide/fade-out (Context.IsOpen == false, _exiting == true) its
    // focus trap + scroll lock + swipe are already torn down by Cleanup(), so the
    // still-painted panel is a clickable/tabbable ghost. pointer-events-none + inert
    // make it inert for the leave: no stray click / Tab re-enters a closing sheet.
    // Focus was restored to the trigger by RemoveFocusTrap at close time, independent
    // of this. The wrapper is pointer-events-none, so the OPEN panel must re-enable
    // pointer-events-auto explicitly — hence the toggle rather than a plain override.
    private string PointerClass => _exiting ? "pointer-events-none" : "pointer-events-auto";
    private string? ExitInert => _exiting ? "true" : null;

    private SheetSize EffectiveSize => SizePreset switch
    {
        Lumeo.Size.Sm => SheetSize.Sm,
        Lumeo.Size.Md => SheetSize.Default,
        Lumeo.Size.Lg => SheetSize.Lg,
        Lumeo.Size.Xl => SheetSize.Xl,
        _ => Size,
    };

    private string SizeClass => Side is Lumeo.Side.Left or Lumeo.Side.Right
        ? EffectiveSize switch
        {
            SheetSize.Sm => "sm:max-w-xs",
            SheetSize.Lg => "sm:max-w-lg",
            SheetSize.Xl => "sm:max-w-xl",
            SheetSize.Full => "sm:max-w-full",
            _ => "sm:max-w-sm"
        }
        // Top/Bottom: width is always full (inset-x-0). Size controls
        // the height — Full takes the entire viewport (mobile-fullscreen
        // pattern), the other sizes cap at a fraction of the viewport
        // height. Default keeps the legacy content-driven height so
        // existing layouts are unchanged.
        : EffectiveSize switch
        {
            SheetSize.Sm => "max-h-[40vh] h-auto",
            SheetSize.Lg => "max-h-[70vh] h-auto",
            SheetSize.Xl => "max-h-[85vh] h-auto",
            SheetSize.Full => "inset-y-0 h-full max-h-full",
            _ => ""
        };

    private string PositionClasses => Side switch
    {
        Lumeo.Side.Top => $"inset-x-0 top-0 {SizeClass}",
        Lumeo.Side.Bottom => $"inset-x-0 bottom-0 {SizeClass}",
        Lumeo.Side.Left => $"inset-y-0 start-0 h-full w-3/4 {SizeClass}",
        Lumeo.Side.Right => $"inset-y-0 end-0 h-full w-3/4 {SizeClass}",
        _ => $"inset-y-0 end-0 h-full w-3/4 {SizeClass}"
    };

    // Animation=Slide is paired with the JS-interop AttachOverlaySlideEnd
    // (see OnAfterRenderAsync) which clears the inline transform once the
    // slide animation completes — this defeats the `animation-fill-mode:
    // both` identity-matrix trap that would otherwise create a containing
    // block for fixed-positioned descendants. Fade / None don't use a
    // transform at all, so no JS cleanup is needed.
    private string AnimationClass => _exiting ? ExitAnimationClass : EnterAnimationClass;

    private string EnterAnimationClass => Animation switch
    {
        SheetAnimation.None => "",
        SheetAnimation.Fade => "animate-fade-in",
        SheetAnimation.Slide => Side switch
        {
            Lumeo.Side.Top => "animate-slide-in-from-top",
            Lumeo.Side.Bottom => "animate-slide-in-from-bottom",
            Lumeo.Side.Left => "animate-slide-in-from-left",
            Lumeo.Side.Right => "animate-slide-in-from-right",
            _ => "animate-slide-in-from-right"
        },
        _ => ""
    };

    // Close counterpart to EnterAnimationClass — the panel slides/fades back out
    // toward its anchor edge while _exiting is true.
    private string ExitAnimationClass => Animation switch
    {
        SheetAnimation.None => "",
        SheetAnimation.Fade => "animate-fade-out",
        SheetAnimation.Slide => Side switch
        {
            Lumeo.Side.Top => "animate-slide-out-to-top",
            Lumeo.Side.Bottom => "animate-slide-out-to-bottom",
            Lumeo.Side.Left => "animate-slide-out-to-left",
            Lumeo.Side.Right => "animate-slide-out-to-right",
            _ => "animate-slide-out-to-right"
        },
        _ => ""
    };

    // Backdrop fades in on open, fades out while the panel exits.
    // While OPEN, pointer-events-auto is REQUIRED: the full-viewport wrapper (line
    // ~20) is pointer-events-none so it never blocks the page, and every hit-target
    // child must re-enable pointer events explicitly (same as DialogContent /
    // DrawerContent / AlertDialogContent, whose backdrops hardcode it). Without it
    // the backdrop inherits none and swallows nothing — click-outside-to-close
    // silently dies for every Sheet (most visible via service-opened sheets, whose
    // only dismiss affordances are the backdrop + Escape). (B10.) While EXITING the
    // scrim KEEPS pointer-events-auto so it goes on shielding the page beneath until
    // it unmounts — a modal backdrop must block the page until it is gone (Radix
    // keeps the overlay blocking until close completes), so a fast double-click
    // during the fade lands on the scrim, not the page below. HandleBackdropClick is
    // already a no-op while exiting (it gates on Context.IsOpen), so swallowing that
    // click can't re-trigger a dismiss/reopen. The PANEL stays pointer-events-none.
    private string BackdropClass => _exiting
        ? "fixed inset-0 animate-fade-out pointer-events-auto"
        : "fixed inset-0 animate-fade-in pointer-events-auto";

    // When exiting with a slide animation the backdrop must fade for the same
    // 300ms that the panel slides, so neither finishes early and leaves the
    // other running solo. animate-fade-out is 0.15s by default (matching
    // fade-in), so we override animation-duration inline for this one case.
    // Fade and None modes don't need an override: Fade uses animate-fade-out
    // directly (same 0.15s for both), None has no exit phase.
    private string BackdropStyle => _exiting && Animation == SheetAnimation.Slide
        ? $"background-color:var(--color-overlay-backdrop);z-index:{BackdropZ};animation-duration:300ms"
        : $"background-color:var(--color-overlay-backdrop);z-index:{BackdropZ}";

    // Kept for backward-compat with tests / consumers that read SideClasses.
    private string SideClasses => $"{PositionClasses} {EnterAnimationClass}".Trim();

    // A scoped <DirectionProvider> wins over the global ThemeService.
    [CascadingParameter(Name = "LumeoDirection")] private LayoutDirection? ScopedDirection { get; set; }
    private LayoutDirection EffectiveDirection => ScopedDirection ?? Theme.CurrentDirection;

    // PositionClasses use logical start/end-0 and the slide keyframes mirror under
    // [dir=rtl], so under RTL a Side.Right sheet rests on (and animates from) the
    // visual LEFT edge — the dismiss-swipe must follow that visual edge too, or an
    // RTL right-side sheet only closes by dragging toward the page. (DrawerContent
    // has the identical fix.)
    private Lumeo.Side EffectiveSide => EffectiveDirection == LayoutDirection.Rtl
        ? Side switch
        {
            Lumeo.Side.Left => Lumeo.Side.Right,
            Lumeo.Side.Right => Lumeo.Side.Left,
            var s => s,
        }
        : Side;

    // Swipe direction is the direction of the gesture that should dismiss the sheet:
    // a Right-anchored sheet flies out to the right when the user swipes right, etc.
    private string SwipeDirection => EffectiveSide switch
    {
        Lumeo.Side.Top => "up",
        Lumeo.Side.Right => "right",
        Lumeo.Side.Bottom => "down",
        Lumeo.Side.Left => "left",
        _ => "right"
    };

    protected override async Task OnParametersSetAsync()
    {
        if (Shell is not null) return;

        // The exit animation is driven ENTIRELY here, from the open->closed render
        // transition — NOT from OnAfterRenderAsync (which only runs its close branch
        // once the open-interop has completed). On Blazor Server the open interop
        // is a chain of round-trips, so a dismiss can land while `_interopReady` is
        // still false; keying the slide-out off `_shownOpen` (flipped true the
        // instant we first render open) makes the panel animate out no matter when
        // the dismiss arrives. Scheduling the unmount here too means the panel can
        // never get stranded mounted with no timer to remove it. (B11.)
        if (Context.IsOpen)
        {
            // Re-opened mid-exit: clear the latch + pending unmount BEFORE this
            // render commits so AnimationClass picks EnterAnimationClass on the
            // first re-open render instead of painting a frame of the slide-OUT. #184
            if (_exiting)
            {
                _exitDispatch.Cancel();
                _exiting = false;
                _exitWired = false;
            }
            _shownOpen = true;
        }
        else if (_shownOpen)
        {
            // First render of the close: latch the slide-out (kept mounted via the
            // Context.IsOpen || _exiting gate). OnAfterRenderAsync then wires the
            // animationend-driven unmount; this timer is the fallback.
            _shownOpen = false;
            if (ExitDurationMs > 0)
            {
                _exiting = true;
                _exitWired = false;
                _exitDispatch.Schedule(ExitDurationMs, () => InvokeAsync(FinishExit));
            }
        }

        // While the sheet stays open, re-evaluate swipe eligibility against the
        // LIVE params (PreventClose / SwipeToClose / SwipeDirection). Without this
        // a toggle of those parameters is ignored until a full close+reopen — the
        // gesture stays registered (or absent) with stale settings. Mirrors
        // DrawerContent.OnParametersSetAsync. #89
        if (_interopReady && Context.IsOpen)
            await ReconcileSwipeAsync();
    }

    // (Re)wires the swipe-to-dismiss gesture to match the current eligibility and
    // direction, unregistering a stale handler first. No-op when nothing changed.
    private async Task ReconcileSwipeAsync()
    {
        var desired = SwipeEligible;
        var direction = SwipeDirection;

        // Already in the right state with the right direction → nothing to do.
        if (desired == _swipeRegistered && (!desired || direction == _registeredSwipeDirection))
            return;

        if (_swipeRegistered)
            await UnregisterSwipeAsync();

        if (desired)
            await RegisterSwipeAsync(direction);
    }

    private async Task RegisterSwipeAsync(string direction)
    {
        await Interop.RegisterDrawerSwipe(_contentId, direction, HandleSwipe, GestureOpts.Value.SwipeDismissThresholdPx, GestureOpts.Value.SwipeDismissFirePx);
        _swipeRegistered = true;
        _registeredSwipeDirection = direction;
    }

    private async Task UnregisterSwipeAsync()
    {
        await Interop.UnregisterDrawerSwipe(_contentId);
        _swipeRegistered = false;
        _registeredSwipeDirection = null;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // When passthrough mode is active the host SheetContent owns scroll lock
        // + focus trap; this nested instance is a no-op for lifecycle effects.
        if (Shell is not null) return;

        if (Context.IsOpen && !_interopReady)
        {
            // Mark BEFORE the awaits so a re-entrant close (Server can dispatch the
            // dismiss click between these round-trips) sees interop as "in progress"
            // and the undo-check below fires exactly once.
            _interopReady = true;
            try
            {
                await Interop.LockScroll();
                await Interop.SetupFocusTrap(_contentId);
                // Native animationend listener sets inline transform:none after
                // the slide animation completes (filtered on slide-in-from-* so
                // descendant zoom-in / fade-in events don't trigger us). Inline
                // style beats the keyframe fill-mode forwarding — guarantees no
                // containing-block trap for popovers.
                if (Animation == SheetAnimation.Slide)
                {
                    await Interop.AttachOverlaySlideEnd(_contentId);
                }
                // Touch swipe-to-dismiss (WCAG 2.5.1 / mobile UX parity with Drawer).
                // Reuses the Drawer JS helper as-is — it already handles all four
                // directions and matches the Sheet's Side parameter 1:1.
                // Gated on SwipeToClose (default false) because Sheets commonly
                // contain scrollable content, and a downward scroll on a Bottom
                // sheet would otherwise be misread as a dismiss gesture.
                // Routed through RegisterSwipeAsync so _swipeRegistered tracks the
                // wiring and OnParametersSetAsync can reconcile a later toggle. #89
                if (SwipeEligible)
                {
                    await RegisterSwipeAsync(SwipeDirection);
                }
            }
            catch (JSDisconnectedException) { }

            // Dismissed while the open interop was still in flight (the Server
            // round-trip window that used to swallow the slide-out): tear the
            // just-registered handlers back down so a focus trap / scroll lock /
            // swipe gesture isn't left bound to a panel that's already sliding out.
            // The slide-out itself is owned by OnParametersSetAsync, so it plays
            // regardless of this.
            if (!Context.IsOpen)
            {
                await Cleanup();
                _interopReady = false;
            }
        }
        else if (!Context.IsOpen && _interopReady)
        {
            // Close: tear down scroll-lock / focus-trap / swipe (focus returns to
            // the trigger now). The slide-out + deferred unmount are already
            // scheduled by OnParametersSetAsync — this branch is interop teardown
            // only.
            await Cleanup();
            _interopReady = false;
        }

        // Radix-Presence parity: hand the unmount to the panel's OWN exit
        // animationend. attachOverlayExitEnd first strips the open-time inline
        // animation:none/transform:none guard (otherwise it OVERRIDES the
        // animate-slide-out-* class and the panel can't move — the B11 root cause),
        // then notifies OnExitAnimationEnd once the slide/fade-out finishes so the
        // backdrop + panel drop together. The _exitDispatch timer stays armed as a
        // fallback. Runs after the exit render has committed the exit class.
        if (_exiting && !_exitWired)
        {
            _exitWired = true;
            _selfRef ??= DotNetObjectReference.Create(this);
            try { await Interop.AttachOverlayExitEnd(_contentId, _selfRef); }
            catch (JSDisconnectedException) { }
        }
    }

    // Invoked from JS (attachOverlayExitEnd) when the panel's exit animation ends.
    // Idempotent with the fallback timer — whichever lands first wins, the other
    // no-ops via the _exiting guard in FinishExit.
    [JSInvokable]
    public Task OnExitAnimationEnd() => InvokeAsync(FinishExit);

    // Ends the exit phase: cancel the fallback timer and drop backdrop + panel in
    // the same render commit (both gated on Context.IsOpen || _exiting).
    private void FinishExit()
    {
        if (!_exiting) return;
        _exitDispatch.Cancel();
        _exiting = false;
        _exitWired = false;
        StateHasChanged();
    }

    // The backdrop / Escape / close paths are inert during the exit phase
    // (Context.IsOpen == false, panel only kept mounted for the slide-out): its
    // modal affordances were already torn down by Cleanup(), so a stray click /
    // Escape must not re-enter the dismiss flow on an already-closing panel. #185
    private Task HandleBackdropClick() => !Context.IsOpen || PreventClose ? Task.CompletedTask : Dismiss("outside");

    private Task HandleCloseButton() => Context.IsOpen ? Dismiss("close") : Task.CompletedTask;

    private Task HandleSwipe() => Dismiss("swipe");

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape" && Context.IsOpen && !PreventClose) await Dismiss("escape");
    }

    private Task Dismiss(string reason) => Context.TryDismiss(reason);

    private async Task Cleanup()
    {
        try
        {
            await Interop.UnregisterDrawerSwipe(_contentId);
            _swipeRegistered = false;
            _registeredSwipeDirection = null;
            await Interop.RemoveFocusTrap(_contentId);
            await Interop.UnlockScroll();
        }
        catch (JSDisconnectedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        _exitDispatch.Dispose();
        _selfRef?.Dispose();
        if (_interopReady) await Cleanup();
    }

    /// <summary>Sheet sizes. <c>Full</c> is layout-intent (entire viewport),
    /// not a scale value, so this enum is intentionally NOT replaced by
    /// <see cref="Lumeo.Size"/> in 3.0.</summary>
    public enum SheetSize { Sm, Default, Lg, Xl, Full }
    public enum SheetAnimation { Slide, Fade, None }
}

